class Solution:
    def canDistribute(self, nums, quantity):
        from collections import Counter
        counts = tuple(sorted(Counter(nums).values(), reverse=True))
        orders = sorted(quantity, reverse=True)
        memo = {}

        def backtrack(idx, remaining):
            if idx == len(orders):
                return True
            key = (idx, remaining)
            if key in memo:
                return memo[key]
            need = orders[idx]
            ok = False
            tried = set()
            for i, have in enumerate(remaining):
                if have in tried or have < need:
                    continue
                tried.add(have)
                nxt = list(remaining)
                nxt[i] -= need
                nxt.sort(reverse=True)
                if backtrack(idx + 1, tuple(nxt)):
                    ok = True
                    break
            memo[key] = ok
            return ok

        return backtrack(0, counts)

