class Solution:
    def canDistribute(self, nums, quantity):
        from collections import Counter
        counts = list(Counter(nums).values())
        m = len(quantity)
        full = 1 << m
        subsum = [0] * full
        for mask in range(1, full):
            low = mask & (-mask)
            idx = low.bit_length() - 1
            subsum[mask] = subsum[mask ^ low] + quantity[idx]
        dp = [False] * full
        dp[0] = True
        for cnt in counts:
            if dp[full - 1]:
                break
            new_dp = dp[:]
            for mask in range(full):
                if not dp[mask]:
                    continue
                rest = (full - 1) ^ mask
                sub = rest
                while sub:
                    if subsum[sub] <= cnt:
                        new_dp[mask | sub] = True
                    sub = (sub - 1) & rest
            dp = new_dp
        return dp[full - 1]

