var canDistribute = function(nums, quantity) {
    const counts = new Map();
    for (const v of nums) counts.set(v, (counts.get(v) || 0) + 1);
    const countList = Array.from(counts.values());
    const m = quantity.length;
    const full = 1 << m;
    const subsum = new Array(full).fill(0);
    for (let mask = 1; mask < full; mask++) {
        const low = mask & (-mask);
        const idx = Math.round(Math.log2(low));
        subsum[mask] = subsum[mask ^ low] + quantity[idx];
    }
    let dp = new Array(full).fill(false);
    dp[0] = true;
    for (const cnt of countList) {
        if (dp[full - 1]) break;
        const newDp = dp.slice();
        for (let mask = 0; mask < full; mask++) {
            if (!dp[mask]) continue;
            const rest = (full - 1) ^ mask;
            let sub = rest;
            while (sub) {
                if (subsum[sub] <= cnt) newDp[mask | sub] = true;
                sub = (sub - 1) & rest;
            }
        }
        dp = newDp;
    }
    return dp[full - 1];
};
